"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[411],{3414:e=>{e.exports=JSON.parse('{"functions":[],"properties":[],"types":[],"name":"Cache","desc":"A simple deduplication cache used to prevent the same event from being processed\\nmore than once. Keyed by the event\'s `endTime` timestamp.\\n\\nBoth the MessagingService subscription (in [AdminAbuse]) and the [Polling] loop\\ncheck this cache before activating an event. If `cache[endTime]` is already `true`,\\nthe event is skipped.\\n\\n```lua\\n-- Internal usage:\\nif cache[endTime] then\\n\\treturn -- already processed\\nend\\ncache[endTime] = true\\n```","realm":["Server"],"since":"0.1.0","private":true,"source":{"line":24,"path":"packages/admin-abuse/src/Cache.luau"}}')}}]);